    /// // Check statistics
    /// Console.WriteLine(cache.GetStats());
    ///
    /// // Persist to disk
    /// await cache.SaveToFileAsync("prompt-cache.json");
    /// var loaded = await PromptCache.LoadFromFileAsync("prompt-cache.json");
