        /// Uses SHA-256 for collision resistance.
        /// </summary>
        /// <param name="prompt">The prompt text.</param>
        /// <param name="model">Optional model name to include in the key.</param>
        /// <returns>A hex-encoded SHA-256 hash.</returns>
        /// <exception cref="ArgumentNullException">
        /// Thrown when <paramref name="prompt"/> is null.
        /// </exception>
        public static string ComputeKey(string prompt, string? model = null)
        {
            if (prompt == null)
                throw new ArgumentNullException(nameof(prompt));

            // Compute the max byte count to avoid intermediate array allocation.
            // For typical ASCII prompts this stack-allocates; for very large
            // prompts (>1 KB encoded) it falls back to a rented array.
            int modelBytes = model != null
                ? Encoding.UTF8.GetMaxByteCount(model.Length) + 2 // "::" separator
                : 0;
            int maxBytes = modelBytes + Encoding.UTF8.GetMaxByteCount(prompt.Length);

            const int StackLimit = 1024;
            byte[]? rented = null;
            Span<byte> buffer = maxBytes <= StackLimit
                ? stackalloc byte[StackLimit]
                : (rented = System.Buffers.ArrayPool<byte>.Shared.Rent(maxBytes));

            try
            {
                int written = 0;
                if (model != null)
                {
                    written = Encoding.UTF8.GetBytes(model.AsSpan(), buffer);
                    buffer[written++] = (byte)':';
                    buffer[written++] = (byte)':';
                }
                written += Encoding.UTF8.GetBytes(prompt.AsSpan(), buffer.Slice(written));

                Span<byte> hash = stackalloc byte[32]; // SHA-256 = 32 bytes
                SHA256.HashData(buffer.Slice(0, written), hash);
                return Convert.ToHexString(hash).ToLowerInvariant();
            }
            finally
            {
                if (rented != null)
                    System.Buffers.ArrayPool<byte>.Shared.Return(rented);
            }
        }

        /// <summary>
        /// Retrieves a cached response for the given prompt.
        /// Returns null on cache miss or if the entry has expired.
        /// Moves the entry to the most-recently-used position on hit.
        /// </summary>
        /// <param name="prompt">The prompt text to look up.</param>
        /// <param name="model">Optional model name (must match what was used in Put).</param>
        /// <returns>The cached entry, or null if not found or expired.</returns>
        /// <exception cref="ArgumentNullException">
        /// Thrown when <paramref name="prompt"/> is null.
        /// </exception>
        public CacheEntry? Get(string prompt, string? model = null)
        {
            if (prompt == null)
                throw new ArgumentNullException(nameof(prompt));

            string key = ComputeKey(prompt, model);

            lock (_lock)
            {
                if (!_map.TryGetValue(key, out var node))
                {
                    _misses++;
                    return null;
                }

                // Check expiration
                if (node.Value.Entry.IsExpired)
                {
                    _order.Remove(node);
                    _map.Remove(key);
                    _evictions++;
                    _misses++;
                    return null;
                }

                // Move to front (most recently used)
                _order.Remove(node);
                _order.AddFirst(node);

                node.Value.Entry.LastAccessedAt = DateTimeOffset.UtcNow;
                node.Value.Entry.AccessCount++;
